const msg = $input.first().json;
// Handle both Gmail Trigger (lowercase, parsed) and Gmail get-message (Capitalized headers)
function header(nm){try{const hs=(msg.payload&&msg.payload.headers)||[];const h=hs.find(x=>(x.name||'').toLowerCase()===nm.toLowerCase());return h?h.value:'';}catch(e){return '';}}
const subject = msg.subject || msg.Subject || header('Subject') || '';
// from can be: {value:[{address}]} (trigger) OR 'Name <addr>' string (get-message From)
function parseFrom(f){
  if(!f) return '';
  if(typeof f === 'object' && f.value && f.value[0]) return f.value[0].address || '';
  const s = String(f);
  const m = s.match(/<([^>]+)>/);
  return m ? m[1] : s.trim();
}
const from_addr = parseFrom(msg.from || msg.From || header('From'));
const msg_id = msg.id || '';
// body: trigger has .text; get-message often only .snippet at top, full text in payload parts
function decode(d){ try { return Buffer.from(d,'base64').toString('utf-8'); } catch(e){ return ''; } }
function walk(p,acc){ if(!p) return; const mt=p.mimeType||''; if(p.body&&p.body.data&&mt.indexOf('text/')===0){acc.push(decode(p.body.data));} if(p.parts){for(const c of p.parts)walk(c,acc);} }
let body = msg.text || msg.textAsHtml || '';
if(!body && msg.payload){ const acc=[]; walk(msg.payload,acc); body=acc.join('\n'); }
if(!body) body = msg.snippet || '';
body = String(body).replace(/<style[\s\S]*?<\/style>/gi,' ').replace(/<[^>]+>/g,' ').replace(/&nbsp;/g,' ').replace(/\s+/g,' ').trim();
const snippet = msg.snippet || body.slice(0,200);
const atts = msg.attachments || [];
const has_attachments = Array.isArray(atts) && atts.length>0;
const filenames = has_attachments ? atts.map(a=>a.filename||a.name).filter(Boolean) : [];
return [{ json: { subject, from_addr, msg_id, body, snippet, has_attachments, filenames } }];

