const raw = $input.first().json.output || '{}';
const clean = raw.replace(/```json|```/g, '').trim();
let extracted = {};
try { extracted = JSON.parse(clean); } catch(e) { extracted = {}; }

const RATES = { USD: 0.385, AED: 0.105, SAR: 0.103, OMR: 1 };
const round3 = (n) => Math.round((n + Number.EPSILON) * 1000) / 1000;

const treatment = (extracted.vat_treatment || 'not_stated').toLowerCase();
const isInclusive = treatment === 'inclusive';

const rfqItems = $('Fetch RFQ Items').all().map(i => i.json);
let subtotalEx = 0;
let rawQuotedTotal = 0;

const bid_items = (extracted.items || []).map(item => {
  const rfqItem = rfqItems.find(r => r.item_id === item.rfq_item_id) || {};
  const qty = parseFloat(rfqItem.quantity) || 1;
  const rate = RATES[item.currency || extracted.currency || 'OMR'] || 1;
  const quotedUnitOmr = (parseFloat(item.unit_price) || 0) * rate;
  const exUnitOmr = round3(isInclusive ? quotedUnitOmr / 1.05 : quotedUnitOmr);
  const exTotalOmr = round3(exUnitOmr * qty);
  subtotalEx += exTotalOmr;
  rawQuotedTotal += round3(quotedUnitOmr * qty);
  return { rfq_item_id: item.rfq_item_id, sap_item_number: item.sap_item_number,
    description: item.description, unit_price: item.unit_price,
    currency: item.currency || extracted.currency || 'OMR',
    unit_price_omr: exUnitOmr, total_price_omr: exTotalOmr,
    ai_confidence: item.confidence || 'medium',
    ai_confidence_reason: item.confidence_reason, notes: item.notes };
});

const subtotal_ex_vat_omr = round3(subtotalEx);
const total_inc_vat_omr = round3(subtotal_ex_vat_omr * 1.05);
const vat_amount_omr = round3(total_inc_vat_omr - subtotal_ex_vat_omr);
const initial_quote_price_omr = round3(rawQuotedTotal);

return [{ json: { extracted, bid_items,
  subtotal_ex_vat_omr, vat_amount_omr, total_inc_vat_omr, initial_quote_price_omr } }];

